-- create helper table
CREATE TABLE `tmp_matching_gameobject_ids` (
  `id` int unsigned NOT NULL DEFAULT '0' COMMENT 'Unique Spawn Identifier'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- add matching spawn ids


-- update max_build to 18414 when available in helper table

UPDATE gameobject_spawns gos
JOIN tmp_matching_gameobject_ids t
    ON t.id = gos.id
SET gos.max_build = 18414
WHERE gos.max_build <> 18414;

-- remove helper table

DROP TABLE `tmp_matching_gameobject_ids`;


